        private void UpdateCompositionCount()
        {
            textBoxCompositionCount.Text = "";

            var checkedSolutions = checkedListBoxMineral.CheckedItems.Cast<SolidSolution>().ToArray();
            int targetCount = (int)numericUpDownMineral_Target.Value;
            double resolution = (double)numericUpDownEndmembers_Resolution.Value / 100;

            int totalCount = 0;

            foreach (var solution in checkedSolutions)
            {
                var comps = solution.Divide(resolution, targetCount);
                if (comps == null)
                {
                    textBoxCompositionCount.Text = "計算出来ません";
                }
                else
                {
                    // 個別の組成数を表示
                    int count = comps.Length;
                    textBoxCompositionCount.Text += $"{solution.Name}: {count} 組成\r\n";
                    totalCount += count;
                    string constraints = string.Join(Environment.NewLine, solution.Constraints);
                    textBoxEndmembers_Constraints.Text = constraints;
                }
            }
            textBoxCompositionCount.Text += $"\r\n合計: {totalCount} 組成";
        }
        #endregion
        #region 選択されている鉱物の条件式、化学組成リストを更新・表示
        private void UpdateSelectedSolution()
        {
            var selectedSolution = checkedListBoxMineral.SelectedItem as SolidSolution;

            if (selectedSolution == null)
            {
                textBoxEndmembers_Constraints.Text = "";
                textBoxEndmembers_CompositionLists.Text = "";
                textBoxMineral_Name.Text = "";
                textBoxMineral_Memo.Text = "";
                return;
            }
            textBoxMineral_Name.Text = selectedSolution.Name;
            textBoxMineral_Memo.Text = selectedSolution.Formula;

            // 条件式を表示
            if (selectedSolution.Constraints != null && selectedSolution.Constraints.Length > 0)
            {
                textBoxEndmembers_Constraints.Text = string.Join("," + Environment.NewLine, selectedSolution.Constraints);
            }
            else
            {
                textBoxEndmembers_Constraints.Text = "";
            }
            // 化学組成リストを表示
            double resolution = (double)numericUpDownEndmembers_Resolution.Value / 100;
            int targetCount = (int)numericUpDownMineral_Target.Value;
            // 固溶体を指定したmol%で分割
            var compositions = selectedSolution.Divide(resolution, targetCount);

            // 分割できなかった場合（resolution=0など）
            if (compositions == null)
            {
                textBoxEndmembers_CompositionLists.Text = "計算できません";
            }
            else
            {
                var outputFile = compositions.Select(data => data.FileName).ToArray();
                textBoxEndmembers_CompositionLists.Text = string.Join(Environment.NewLine, outputFile);
            }
        }
