        #region リストに追加・更新・削除・初期化メソッド
        #region 追加メソッド
        private void buttonAddList_Click(object sender, EventArgs e)
        {
            var members = new List<Mineral>();

            foreach (var comp in endmemberControls)
            {
                if (string.IsNullOrWhiteSpace(comp.EndmemberName))
                    continue;
                var mineral = new Mineral(comp.EndmemberName, comp.EndmemberFormula);
                members.Add(mineral);
            }
            if (members.Count == 0)
                return;

            string MineralName = textBoxMineral_Name.Text.Trim(); //Trim()は文字列の先頭と末尾に付いている空白文字を削除
            string Memo = textBoxMineral_Memo.Text.Trim();
            var constraints = textBoxEndmembers_Constraints.Text
                .Split(',', StringSplitOptions.RemoveEmptyEntries) // ,で分割
                .Select(s => s.Trim())               // 各行の前後の空白を削除
                .Where(s => !string.IsNullOrEmpty(s)) // 空行を除外
                .ToArray();
            var newSolution = new SolidSolution(MineralName, Memo, members.ToArray(), constraints);
            SolidSolution[] existingSs;
            XmlSerializer xml = new XmlSerializer(typeof(SolidSolution[]));

            // XMLファイルから既存のデータを読み込み
            string xmlPath = AssemblyPath + "\\MineralDatabase.xml";
            var fs1 = new FileStream(xmlPath, FileMode.Open);
            existingSs = (SolidSolution[])xml.Deserialize(fs1);
            fs1.Close();

            var updatedSolutions = existingSs.Append(newSolution).ToArray();

            var fs2 = new FileStream(xmlPath, FileMode.Create);
            xml.Serialize(fs2, updatedSolutions);
            fs2.Close();

            checkedListBoxMineral.DisplayMember = "Name";
            checkedListBoxMineral.DataSource = updatedSolutions;
        }
        #endregion
        #region 更新メソッド
        private void buttonUpdate_Click(object sender, EventArgs e)
        {
            int selectedIndex = checkedListBoxMineral.SelectedIndex;
            var members = new List<Mineral>();
            string xmlPath = AssemblyPath + "\\MineralDatabase.xml";
            SolidSolution[] existingSs;
            XmlSerializer xml = new XmlSerializer(typeof(SolidSolution[]));

            foreach (var comp in endmemberControls)
            {
                if (string.IsNullOrWhiteSpace(comp.EndmemberName))
                    continue;
                var mineral = new Mineral(comp.EndmemberName, comp.EndmemberFormula);
                members.Add(mineral);
            }
            if (members.Count == 0)
                return;

            string MineralName = textBoxMineral_Name.Text.Trim(); //Trim()は文字列の先頭と末尾に付いている空白文字を削除
            string Memo = textBoxMineral_Memo.Text.Trim();
            var constraints = textBoxEndmembers_Constraints.Text
                .Split(',', StringSplitOptions.RemoveEmptyEntries) // ,で分割
                .Select(s => s.Trim())               // 各行の前後の空白を削除
                .Where(s => !string.IsNullOrEmpty(s)) // 空行を除外
                .ToArray();
            var newSs = new SolidSolution(MineralName, Memo, members.ToArray(), constraints);
            var fs1 = new FileStream(xmlPath, FileMode.Open);
            existingSs = (SolidSolution[])xml.Deserialize(fs1);
            fs1.Close();

            existingSs[selectedIndex] = newSs;
            var fs2 = new FileStream(xmlPath, FileMode.Create);
            xml.Serialize(fs2, existingSs);
