        private void buttonMineral_Reset_Click(object sender, EventArgs e)
        {
            XmlSerializer xml = new XmlSerializer(typeof(SolidSolution[]));
            string originalPath = AssemblyPath + "\\MineralDatabaseOriginal.xml";
            string xmlPath = AssemblyPath + "\\MineralDatabase.xml";
            File.Copy(originalPath, xmlPath, true); //オリジナルをコピー
            var fs = new FileStream(xmlPath, FileMode.Open);
