        //分類モデル
        private async void buttonModel_Train_Click(object sender, EventArgs e)
        {
            //  学習対象の鉱物リストを作成
            var targetMinerals = new List<string>();
            foreach (var item in checkedListBoxTrainMinerals.CheckedItems)
            {
                targetMinerals.Add(item.ToString());
            }

            if (targetMinerals.Count == 0)
                return;


            string rootPath = textBoxModel_Teacher.Text;
            string savePath = textBoxModel_Save.Text;
            int epochs = (int)numericUpDownModel_Epochs.Value;
            int batchSize = (int)numericUpDownModel_BatchSize.Value;
            int patience = (int)numericUpDownModel_EaryStopping.Value;
            float testSplit = (float)numericUpDownModel_ValidationSplit.Value / 100f;

            // パスチェック
            if (!Directory.Exists(rootPath))
            {
                MessageBox.Show("訓練データフォルダが見つかりません。", "エラー", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }
            if (string.IsNullOrWhiteSpace(savePath))
            {
                // 未指定ならデスクトップにModelsフォルダを作成
                savePath = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Desktop), "Models");
            }

            //  UIロックとログクリア
            buttonModel_Train.Enabled = false;
            textBoxModel_Evaluation.Clear();

            //  バックグラウンドで学習を実行 (引数で全部渡す)
            await Task.Run(() => _DeepLearning.RunTraining(targetMinerals, rootPath, epochs, batchSize, patience, testSplit, savePath));
            //  完了処理
            buttonModel_Train.Enabled = true;
        }
        private async void buttonPrediction_Click(object sender, EventArgs e)
        {
            buttonPrediction.Enabled = false;
            textBoxPredicition_Result.Clear();

            string modelPath = textBoxLoadModel.Text;
            var files = new List<string>();
            foreach (var item in listBoxPrediction_Failes.Items)
            {
                files.Add(item.ToString());
            }

            await Task.Run(() => {
                var predictDeepLearning = new DeepLearning(PredictionLog);
                predictDeepLearning.RunPrediction(modelPath, files, AssemblyPath);
            });

            buttonPrediction.Enabled = true;
        }

